func (cfg *Cfg) readLDAPConfig() {
        ldapSec := cfg.Raw.Section("auth.ldap")
        cfg.LDAPConfigFilePath = ldapSec.Key("config_file").String()
        cfg.LDAPSyncCron = ldapSec.Key("sync_cron").String()
