  "architecture": {
    "config_loading_pipeline": {
      "description": "The configuration loading pipeline is orchestrated by Cfg.Load → loadConfiguration → parseINIFile. The pipeline has a strict precedence order:",
      "steps": [
        {
          "order": 1,
          "action": "Load conf/defaults.ini",
          "function": "loadConfiguration",
          "detail": "ini.Load(defaultConfigFile) creates the master *ini.File with all default values."
        },
        {
          "order": 2,
          "action": "Apply command-line default overrides",
          "function": "applyCommandLineDefaultProperties",
          "detail": "Processes --cfg:default.section.key=value args, overriding defaults before custom.ini is merged."
        },
        {
          "order": 3,
          "action": "Merge custom.ini (or specified config file)",
          "function": "loadSpecifiedConfigFile",
          "detail": "Loads conf/custom.ini (or the file specified by --config). Merges each key into the master ini.File, creating sections/keys as needed."
        },
        {
          "order": 4,
          "action": "Apply environment variable overrides",
          "function": "applyEnvVariableOverrides",
          "detail": "For every section+key, computes GF_SECTION_KEY and calls os.Getenv. Non-empty values overwrite the ini.Key. Redacted overrides are logged."
        },
        {
          "order": 5,
          "action": "Apply command-line property overrides",
          "function": "applyCommandLineProperties",
          "detail": "Processes --cfg:section.key=value args with highest precedence."
        },
        {
          "order": 6,
          "action": "Expand interpolation tokens",
          "function": "expandConfig",
          "detail": "Resolves ${ENV_VAR} and $__file{/path} tokens in all values via the registered expander pipeline."
        },
        {
          "order": 7,
          "action": "Initialize logging",
          "function": "initLogging → log.ReadLoggingConfig",
          "detail": "Reads [log] section from the now-fully-merged ini.File to configure log handlers."
        },
        {
          "order": 8,
          "action": "Parse all settings into Cfg fields",
          "function": "parseINIFile",
          "detail": "Stores the ini.File in cfg.Raw, then calls every read*Settings function to populate typed Cfg fields."
        }
      ]
    },
    "env_var_override_mechanisms": {
      "description": "Two distinct mechanisms handle environment variable overrides:",
      "mechanisms": [
        {
          "name": "Startup-time override (applyEnvVariableOverrides)",
          "scope": "All sections and keys",
          "timing": "Once, during loadConfiguration before parseINIFile",
          "key_format": "GF_<SECTION>_<KEY> (uppercase, dots/hyphens → underscores)",
          "example": "GF_AUTH_PROXY_ENABLED overrides [auth.proxy] enabled"
        },
        {
          "name": "Runtime override (DynamicSection / SectionWithEnvOverrides)",
          "scope": "Specific sections that call SectionWithEnvOverrides",
          "timing": "At each Key() call, re-checking the environment",
          "key_format": "Same GF_<SECTION>_<KEY> format via EnvKey()",
          "example": "Used by [auth.extended_jwt] and [auth.passwordless] sections",
          "note": "Allows env vars set after startup to take effect without restart for these sections"
        }
      ]
    },
    "sensitive_value_masking": {
      "description": "Sensitive values are masked at two points: when logging applied overrides, and when building the SettingsBag for the API.",
      "masking_function": "RedactedValue(envKey, value string) string",
      "masking_patterns": [
        "PASSWORD", "SECRET", "PROVIDER_CONFIG", "PRIVATE_KEY", "SECRET_KEY",
        "CERTIFICATE", "ACCOUNT_KEY", "ENCRYPTION_KEY", "VAULT_TOKEN",
        "CLIENT_SECRET", "ENTERPRISE_LICENSE", "API_DB_PASS",
        "^TOKEN$", "*_ID_FORWARDING_TOKEN", "*_AUTHENTICATION_TOKEN",
        "*_AUTH_TOKEN", "*_RENDERER_TOKEN", "*_API_TOKEN",
        "*_WEBHOOK_TOKEN", "*_INSTALL_TOKEN"
      ],
      "exceptions": ["RUDDERSTACK", "APPLICATION_INSIGHTS", "SENTRY"],
      "url_redaction": "RedactedURL strips userinfo from URLs using url.URL.Redacted()",
      "api_masking_point": "OSSImpl.Current() applies RedactedValue to every key before returning the SettingsBag",
      "log_masking_points": [
        "applyEnvVariableOverrides: logs redacted value when recording applied env overrides",
        "DynamicSection.Key: logs redacted value when a runtime env override is applied",
        "applyCommandLineDefaultProperties: logs redacted value for default CLI overrides"
      ]
    },
    "api_admin_settings_flow": {
      "endpoint": "GET /api/admin/settings",
      "handler": "HTTPServer.AdminGetSettings (pkg/api/admin.go:29)",
      "flow": [
        "1. hs.SettingsProvider.Current() → OSSImpl.Current() builds SettingsBag with RedactedValue applied to all keys",
        "2. getAuthorizedSettings(ctx, user, bag) applies RBAC filtering:",
        "   a. Check settings:read + settings:* → return full bag",
        "   b. Per section: check settings:read + settings:<section>:* → include whole section",
        "   c. Per key: check settings:read + settings:<section>:<key> → include individual key",
        "3. Return HTTP 200 JSON with the filtered, redacted SettingsBag"
      ],
      "rbac_scopes": [
        "settings:*  (full access)",
        "settings:<section>:*  (section-level access)",
        "settings:<section>:<key>  (key-level access)"
      ]
    },
    "default_values_pattern": {
      "description": "Defaults are provided at two levels:",
      "levels": [
        {
          "level": "File-level defaults",
          "source": "conf/defaults.ini",
          "mechanism": "Loaded first by loadConfiguration; every key has an explicit default value in this file."
        },
        {
          "level": "Code-level defaults",
          "source": "read*Settings functions",
          "mechanism": "Each function uses ini.Key.MustString(default), MustBool(default), MustInt(default), MustDuration(default), or the valueAsString helper. These serve as fallbacks when a key is absent from all INI files."
        }
      ]
    }
  }
